<template>
    <div>
    <q-carousel
      v-model="slide"
      swipeable
      animated
      control-type="flat"
      control-color="black"
      navigation
      padding
      arrows
      height="fit-content"
    >
      <q-carousel-slide  v-for="(s,index) in props.src" v-bind:key="s" v-bind:name="index" >
        <q-img
          :src="s"
          height="80px"
          width="80px"
        >
        <q-badge @click="deleteImg(s)" color="red" transparent rounded><q-icon name='close'></q-icon></q-badge>
        </q-img>
      </q-carousel-slide>
      <q-carousel-slide :name="props.src.length+1" class="column no-wrap flex-center" key="uploader_carosule3l4h">
        <!--<Uploader :index="props.index" :col="props.col" :hide-upload-btn="false" multiple @upload-success="handleUploadSuccess" @upload-error="handleUploadError" @upload=""/>-->
        <Uploader
        :index="props.index"
        :col="props.col"
        :hide-upload-btn="false"
        multiple
        @upload-success="handleUploadSuccess"
        @upload-error="handleUploadError"
        >
        <template #uploading="{ isUploading }">
            <div v-if="isUploading">
            Uploading: {{ uploadProgress }}%
            </div>
        </template>
        </Uploader>

      </q-carousel-slide>
      </q-carousel>
    </div>  
</template>
<script>
import Uploader from '../Uploader.vue'
import { ref } from 'vue'
export default {
    name:"AdminImages",
    components: {
        Uploader
    },
    props:{
        props: {
            type: Object,
            required: true
        },
    },
    data(){
        return{
            slide: 1?this.props.src.length+1:0,
        }
    },
    methods:{
        handleUploadError(err){
        console.log(err)
        },
        handleUploadSuccess(index,url) {
        console.log('handleUploadSuccess')
        console.log(index,url,this.props.src)
        console.log(Array.from(this.props.src).push(url))
        var payload = {
            index: index,
            value:[...this.props.src,url],
            col: this.props.col
        }
        this.$emit('update', payload)
    },
    deleteImg(src){
        console.log("called")
        var payload = {
            index: this.props.index,
            value: this.props.src.filter(s=>s!==src),
            col: this.props.col
        }
        this.$emit('update', payload)

    }
    }
}
</script>